  ON review_competency_ratings FOR SELECT
  TO authenticated
  USING (
    employee_id = (select auth.uid())
    OR EXISTS (
      SELECT 1 FROM review_monthly_sessions
      WHERE id = review_id
      AND manager_id = (select auth.uid())
